local speed = 3
local startPos = 2000
local endPos = -1500

while true do
	for i = startPos, endPos, -speed do
		text.Position = UDim2.new(0, i, 0, 15)
		shadow.Position = UDim2.new(0, i + 2, 0, 17)
		wait(0.01)
	end
	
	wait(3)
	
	text.Position = UDim2.new(0, startPos, 0, 15)
	shadow.Position = UDim2.new(0, startPos + 2, 0, 17)
	
	wait(2)
end
